/* ══════════════════════════════════════
   FLIEGERMADCHEN LOADER — Effect Toggles
   Set any to false to disable
══════════════════════════════════════ */
const FX={stars:true,bokeh:true,vignette:true,scanlines:true,sweep:true,particles:true,glow:true,pulse:true,lockFlash:true,btnGlow:true,tagline:true,screenFlash:true};

if(!FX.stars)document.querySelector('.fx-stars')?.remove();
if(!FX.bokeh)document.querySelector('.fx-bokeh')?.remove();
if(!FX.vignette)document.querySelector('.fx-vignette')?.remove();
if(!FX.scanlines)document.querySelector('.fx-scanlines')?.remove();
if(!FX.sweep)document.querySelector('.fx-sweep')?.remove();
if(!FX.glow)document.getElementById('logo-svg')?.classList.remove('fx-glow');
if(!FX.pulse)document.getElementById('logo-svg')?.classList.remove('fx-pulse');
if(!FX.btnGlow)document.getElementById('enter-btn')?.classList.remove('fx-btn-glow');
if(!FX.tagline)document.querySelector('.fx-tagline')?.remove();
if(!FX.screenFlash)document.getElementById('fx-flash')?.remove();

/* Scroll Lock */
document.body.style.overflow='hidden';
window.scrollTo(0,0);

/* Stars */
if(FX.stars){const c=document.getElementById('fx-stars');for(let i=0;i<80;i++){const s=document.createElement('div');s.className='star';s.style.left=Math.random()*100+'%';s.style.top=Math.random()*100+'%';s.style.setProperty('--dur',(2+Math.random()*4)+'s');s.style.setProperty('--delay',(Math.random()*3)+'s');s.style.setProperty('--max-opacity',(0.2+Math.random()*0.6).toString());s.style.width=s.style.height=(1+Math.random()*2)+'px';c.appendChild(s)}}

/* Bokeh */
if(FX.bokeh){const c=document.getElementById('fx-bokeh');const cols=['rgba(232,53,139,0.15)','rgba(139,53,232,0.1)','rgba(53,139,232,0.08)'];for(let i=0;i<5;i++){const o=document.createElement('div');o.className='orb';const sz=100+Math.random()*200;o.style.width=o.style.height=sz+'px';o.style.left=(10+Math.random()*80)+'%';o.style.top=(10+Math.random()*80)+'%';o.style.background=cols[Math.floor(Math.random()*cols.length)];o.style.setProperty('--dur',(6+Math.random()*6)+'s');o.style.setProperty('--delay',(Math.random()*4)+'s');o.style.setProperty('--max-opacity',(0.3+Math.random()*0.4).toString());c.appendChild(o)}}

/* Particles */
if(FX.particles){const c=document.getElementById('fx-particles');function sp(){const p=document.createElement('div');p.className='particle';const a=Math.random()*Math.PI*2,d=60+Math.random()*100;p.style.left=(Math.random()-.5)*80+'px';p.style.top=(Math.random()-.5)*80+'px';const sz=2+Math.random()*3;p.style.width=p.style.height=sz+'px';c.appendChild(p);p.animate([{opacity:.8,transform:'translate(0,0) scale(1)'},{opacity:0,transform:`translate(${Math.cos(a)*d}px,${Math.sin(a)*d}px) scale(0)`}],{duration:800+Math.random()*600,easing:'ease-out'});setTimeout(()=>p.remove(),1500)}let pi=setInterval(sp,60);setTimeout(()=>clearInterval(pi),2200)}

/* Split-Flap */
const TT="READY FOR TAKEOFF",CH="ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789",bn=document.getElementById('enter-btn');
TT.split('').forEach(c=>{const t=document.createElement('span');t.className=c===' '?'flap-char space':'flap-char';t.dataset.target=c;t.textContent=c===' '?'':CH[Math.floor(Math.random()*CH.length)];bn.appendChild(t)});
setTimeout(()=>{document.querySelectorAll('.flap-char:not(.space)').forEach((t,i)=>{const tg=t.dataset.target;let f=0;const tf=6+Math.floor(Math.random()*8);setTimeout(()=>{const iv=setInterval(()=>{f++;if(f>=tf){t.textContent=tg;if(FX.lockFlash)t.classList.add('locked');clearInterval(iv)}else t.textContent=CH[Math.floor(Math.random()*CH.length)]},40)},i*35)})},2200);

/* Spotify */
let ec=null,ip=false;
window.onSpotifyIframeApiReady=(API)=>{const el=document.getElementById('embed-iframe');API.createController(el,{uri:'spotify:track:6SFfjZzuqpo2fb62b1qJSD',width:'300',height:'80'},(ctrl)=>{ec=ctrl;ctrl.addListener('playback_update',e=>{ip=!e.data.isPaused;document.getElementById('icon-play').style.display=ip?'none':'block';document.getElementById('icon-pause').style.display=ip?'block':'none';const cv=document.getElementById('player-cover');ip?cv.classList.add('spinning'):cv.classList.remove('spinning');if(e.data.duration>0)document.getElementById('progress-bar').style.width=(e.data.position/e.data.duration*100)+'%'})})};
function togglePlay(){if(ec)ec.togglePlay()}
function skipPrev(){if(ec)ec.loadUri('spotify:track:6SFfjZzuqpo2fb62b1qJSD')}
function skipNext(){if(ec)ec.togglePlay()}

/* Enter */
function enterSite(){
  if(FX.screenFlash){const f=document.getElementById('fx-flash');if(f)f.classList.add('fire')}
  if(ec)ec.togglePlay();
  document.getElementById('custom-player').classList.add('active');
  document.getElementById('loader').classList.add('hidden');
  document.body.classList.add('loader-done');

  /* Unlock scroll + force to top */
  document.body.style.overflow='';
  window.scrollTo(0,0);

  /* Nochmal nach kurzer Pause — falls Browser noch rendert */
  requestAnimationFrame(()=>{
    window.scrollTo(0,0);
  });
}
